CREATE TABLE enrolled_2025 (
  student_id INT,
  name       VARCHAR(50)
);

CREATE TABLE enrolled_2026 (
  student_id INT,
  name       VARCHAR(50)
);

INSERT INTO enrolled_2025 VALUES
  (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave'),(5,'Eve');

INSERT INTO enrolled_2026 VALUES
  (1,'Alice'),(3,'Carol'),(6,'Frank'),(7,'Grace'),(5,'Eve');

-- INTERSECT: students enrolled in BOTH years (returning students)
SELECT name FROM enrolled_2025
INTERSECT
SELECT name FROM enrolled_2026
ORDER BY name;

-- EXCEPT: students from 2025 who did NOT return in 2026 (dropped out)
SELECT name FROM enrolled_2025
EXCEPT
SELECT name FROM enrolled_2026
ORDER BY name;

-- New students in 2026 who weren't in 2025
SELECT name FROM enrolled_2026
EXCEPT
SELECT name FROM enrolled_2025
ORDER BY name;

CREATE TABLE q1_customers (customer_id INT, name VARCHAR(50));
CREATE TABLE q2_customers (customer_id INT, name VARCHAR(50));
CREATE TABLE q3_customers (customer_id INT, name VARCHAR(50));

INSERT INTO q1_customers VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave');
INSERT INTO q2_customers VALUES (1,'Alice'),(3,'Carol'),(5,'Eve'),(6,'Frank');
INSERT INTO q3_customers VALUES (1,'Alice'),(2,'Bob'),(5,'Eve'),(7,'Grace');

-- Loyal customers: in ALL 3 quarters
SELECT name FROM q1_customers
INTERSECT
SELECT name FROM q2_customers
INTERSECT
SELECT name FROM q3_customers;

-- Q1 churned: ordered in Q1 but not in Q2 or Q3
SELECT name FROM q1_customers
EXCEPT
(
  SELECT name FROM q2_customers
  UNION
  SELECT name FROM q3_customers
);

-- Total unique customers across all quarters
SELECT COUNT(*) AS total_unique_customers FROM (
  SELECT name FROM q1_customers
  UNION
  SELECT name FROM q2_customers
  UNION
  SELECT name FROM q3_customers
) all_customers;
